"""Deterministic AST classifier for raw os.getenv/os.environ.get sites in src/polaris_graph.

Classifies every real Call node os.getenv("KEY", <default>) / os.environ.get("KEY", <default>)
into: MIGRATABLE (single-line string/None literal default, safe), SECRET, COMPUTED (non-literal /
multiline default or no default), and detects CONFLICTS (same key, different literal at diff sites)
and DOUBLE-DEFS (key already in registry).

Only ANALYSIS here — no edits. Prints counts + writes a JSON plan.
"""
from __future__ import annotations

import ast
import json
import os
import sys

ROOT = "/home/polaris/wt/gateinv"
SRC = os.path.join(ROOT, "src/polaris_graph")

sys.path.insert(0, ROOT)
from src.polaris_graph.config_defaults import CONFIG_DEFAULTS  # noqa: E402

SECRET_MARKERS = ("_KEY", "_TOKEN", "_SECRET", "_PASSWORD", "_CREDENTIAL", "CREDENTIALS", "_APIKEY")


def is_secret(key: str) -> bool:
    up = key.upper()
    return any(m in up for m in SECRET_MARKERS)


def literal_default(node: ast.AST):
    """Return (is_literal_str_or_none, value) for a default arg node.

    Only str constants and the None constant are registrable static literals.
    Everything else (f-strings, calls, names, bools/ints via os.getenv? no —
    os.getenv default is always str|None) is non-literal -> COMPUTED.
    """
    if isinstance(node, ast.Constant):
        if node.value is None:
            return True, None
        if isinstance(node.value, str):
            return True, node.value
    return False, None


def is_getenv_call(call: ast.Call):
    """Return ('getenv'|'environ_get'|None). Guards against rebinding by checking exact attr chain."""
    f = call.func
    if isinstance(f, ast.Attribute):
        # os.getenv(...)
        if f.attr == "getenv" and isinstance(f.value, ast.Name) and f.value.id == "os":
            return "getenv"
        # os.environ.get(...)
        if (
            f.attr == "get"
            and isinstance(f.value, ast.Attribute)
            and f.value.attr == "environ"
            and isinstance(f.value.value, ast.Name)
            and f.value.value.id == "os"
        ):
            return "environ_get"
    return None


def file_rebinds_os_or_resolve(tree: ast.AST) -> bool:
    """Whole-file guard: os locally rebound, or 'resolve' locally defined/assigned/imported-as-other."""
    for n in ast.walk(tree):
        # os = ...  or  import os as X (fine) ; but `os =` assignment is a rebind
        if isinstance(n, ast.Assign):
            for t in n.targets:
                if isinstance(t, ast.Name) and t.id in ("os", "resolve"):
                    return True
        if isinstance(n, (ast.FunctionDef, ast.AsyncFunctionDef)):
            if n.name == "resolve":
                return True
            for a in n.args.args + n.args.kwonlyargs + n.args.posonlyargs:
                if a.arg in ("os", "resolve"):
                    return True
        # import something as os / as resolve
        if isinstance(n, (ast.Import, ast.ImportFrom)):
            for alias in n.names:
                bound = alias.asname or alias.name.split(".")[0]
                if bound == "resolve" and not (
                    isinstance(n, ast.ImportFrom)
                    and n.module == "src.polaris_graph.settings"
                    and alias.name == "resolve"
                ):
                    return True
                if bound == "os" and alias.name != "os":
                    return True
    return False


def main():
    plan = {}  # relpath -> list of site dicts
    key_literals = {}  # key -> set of frozen defaults seen (for conflict detection) at MIGRATABLE sites
    stats = {
        "files_scanned": 0,
        "total_calls": 0,
        "migratable": 0,
        "secret": 0,
        "computed_no_default": 0,
        "computed_nonliteral": 0,
        "rebound_file_skipped": 0,
        "environ_subscript": 0,
    }

    for dirpath, _, files in os.walk(SRC):
        for fn in files:
            if not fn.endswith(".py"):
                continue
            path = os.path.join(dirpath, fn)
            rel = os.path.relpath(path, ROOT)
            src = open(path, encoding="utf-8").read()
            try:
                tree = ast.parse(src)
            except SyntaxError:
                continue
            stats["files_scanned"] += 1
            rebound = file_rebinds_os_or_resolve(tree)

            for node in ast.walk(tree):
                if not isinstance(node, ast.Call):
                    continue
                kind = is_getenv_call(node)
                if kind is None:
                    continue
                stats["total_calls"] += 1
                # first positional arg = key
                if not node.args or not isinstance(node.args[0], ast.Constant) or not isinstance(node.args[0].value, str):
                    # dynamic key -> computed
                    stats["computed_nonliteral"] += 1
                    continue
                key = node.args[0].value
                # default = second positional arg
                default_node = node.args[1] if len(node.args) >= 2 else None
                # keyword default? os.getenv has no kw default; os.environ.get(key, default) also positional.
                if default_node is None:
                    # os.getenv("K") -> default None. Registrable as None IF matches, but leave computed:
                    # a bare no-default read returns None; resolve requires registry. Treat as migratable-None.
                    is_lit, val = True, None
                else:
                    is_lit, val = literal_default(default_node)

                site = {
                    "file": rel,
                    "lineno": node.lineno,
                    "col": node.col_offset,
                    "end_lineno": node.end_lineno,
                    "end_col": node.end_col_offset,
                    "kind": kind,
                    "key": key,
                    "default": val,
                    "has_default": default_node is not None,
                    "multiline": node.end_lineno != node.lineno,
                }

                if is_secret(key):
                    site["class"] = "secret"
                    stats["secret"] += 1
                elif not is_lit:
                    site["class"] = "computed_nonliteral"
                    stats["computed_nonliteral"] += 1
                elif site["multiline"]:
                    site["class"] = "computed_multiline"
                    stats["computed_nonliteral"] += 1
                elif rebound:
                    site["class"] = "rebound_file"
                    stats["rebound_file_skipped"] += 1
                else:
                    site["class"] = "migratable"
                    stats["migratable"] += 1
                    key_literals.setdefault(key, set()).add(val)

                plan.setdefault(rel, []).append(site)

    # conflict detection among MIGRATABLE literals, AND against existing registry
    conflicts = {}
    for key, defs in key_literals.items():
        reg_has = key in CONFIG_DEFAULTS
        if len(defs) > 1:
            conflicts[key] = sorted([d if d is not None else "<None>" for d in defs])
        elif reg_has:
            reg_val = CONFIG_DEFAULTS[key]
            only = next(iter(defs))
            if reg_val != only:
                conflicts[key] = sorted(
                    set([reg_val if reg_val is not None else "<None>", only if only is not None else "<None>"])
                )

    # Demote conflict-key sites out of migratable
    conflict_keys = set(conflicts)
    for rel, sites in plan.items():
        for s in sites:
            if s["class"] == "migratable" and s["key"] in conflict_keys:
                s["class"] = "conflicting"

    stats["migratable"] = sum(1 for sites in plan.values() for s in sites if s["class"] == "migratable")
    stats["conflicting_sites"] = sum(1 for sites in plan.values() for s in sites if s["class"] == "conflicting")

    out = {"stats": stats, "conflicts": conflicts, "plan": plan}
    with open("/tmp/config_plan.json", "w") as f:
        json.dump(out, f, indent=2)

    print(json.dumps(stats, indent=2))
    print("\nCONFLICTS (owner-decision, left raw):")
    for k, v in sorted(conflicts.items()):
        print(f"  {k}: {v}")

    # distinct migratable keys, how many already in registry (double-defs) vs new
    mig_keys = {s["key"]: s["default"] for sites in plan.values() for s in sites if s["class"] == "migratable"}
    dbl = {k for k in mig_keys if k in CONFIG_DEFAULTS}
    new = {k for k in mig_keys if k not in CONFIG_DEFAULTS}
    print(f"\nMIGRATABLE distinct keys: {len(mig_keys)}")
    print(f"  already in registry (double-def, agree): {len(dbl)}")
    print(f"  new to registry: {len(new)}")
    print("  NEW KEYS:", sorted(new))


if __name__ == "__main__":
    main()

